    refresh_token_encrypted TEXT,
    synced_at TIMESTAMP,
    created_at TIMESTAMP NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS payment_gateway_events (
    id UUID PRIMARY KEY,
    payment_id UUID REFERENCES payments(id),
    gateway_name VARCHAR(80) NOT NULL,
