CREATE TABLE IF NOT EXISTS family_accounts (id UUID PRIMARY KEY, tenant_id UUID NOT NULL, holder_client_id UUID NOT NULL, name VARCHAR(120) NOT NULL, created_at TIMESTAMP DEFAULT NOW());
