CREATE TABLE IF NOT EXISTS customer_wishlist (id UUID PRIMARY KEY, tenant_id UUID NOT NULL, client_id UUID NOT NULL, product_id UUID, service_id UUID, created_at TIMESTAMP DEFAULT NOW());
