-- SOURCE: ScriptsSQL/129_business_wallet.sql
-- ======================================================================

-- 129_business_wallet.sql
CREATE TABLE IF NOT EXISTS business_wallets (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  branch_id BIGINT NULL,
  status VARCHAR(30) NOT NULL DEFAULT 'ACTIVE',
  currency_code CHAR(3) NOT NULL DEFAULT 'BRL',
  created_at TIMESTAMP NOT NULL DEFAULT NOW(),
  updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
  UNIQUE(tenant_id, branch_id)
);
CREATE TABLE IF NOT EXISTS business_wallet_balances (
  id BIGSERIAL PRIMARY KEY,
  wallet_id BIGINT NOT NULL REFERENCES business_wallets(id),
  available_balance NUMERIC(14,2) NOT NULL DEFAULT 0,
  future_balance NUMERIC(14,2) NOT NULL DEFAULT 0,
  blocked_balance NUMERIC(14,2) NOT NULL DEFAULT 0,
  chargeback_reserve NUMERIC(14,2) NOT NULL DEFAULT 0,
  updated_at TIMESTAMP NOT NULL DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS business_wallet_transactions (
  id BIGSERIAL PRIMARY KEY,
  wallet_id BIGINT NOT NULL REFERENCES business_wallets(id),
  transaction_type VARCHAR(40) NOT NULL,
  direction VARCHAR(10) NOT NULL,
  amount NUMERIC(14,2) NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'PENDING',
  reference_code VARCHAR(120) NULL,
  metadata_json JSONB NULL,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS receivables (
  id BIGSERIAL PRIMARY KEY,
  wallet_id BIGINT NOT NULL REFERENCES business_wallets(id),
  source_type VARCHAR(40) NOT NULL,
  gross_amount NUMERIC(14,2) NOT NULL,
  net_amount NUMERIC(14,2) NOT NULL,
  fee_amount NUMERIC(14,2) NOT NULL DEFAULT 0,
  expected_settlement_date DATE NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'OPEN',
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS receivable_schedules (
  id BIGSERIAL PRIMARY KEY,
  receivable_id BIGINT NOT NULL REFERENCES receivables(id),
  installment_number INT NOT NULL,
  due_date DATE NOT NULL,
  amount NUMERIC(14,2) NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
);
CREATE TABLE IF NOT EXISTS payout_accounts (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  account_name VARCHAR(120) NOT NULL,
  provider_name VARCHAR(60) NOT NULL DEFAULT 'MOCK_PROVIDER',
  account_token VARCHAR(120) NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT TRUE,
  created_at TIMESTAMP NOT NULL DEFAULT NOW()
);
CREATE TABLE IF NOT EXISTS payout_requests (
  id BIGSERIAL PRIMARY KEY,
  wallet_id BIGINT NOT NULL REFERENCES business_wallets(id),
  payout_account_id BIGINT NOT NULL REFERENCES payout_accounts(id),
  requested_amount NUMERIC(14,2) NOT NULL,
  fee_amount NUMERIC(14,2) NOT NULL DEFAULT 0,
  status VARCHAR(20) NOT NULL DEFAULT 'REQUESTED',
  requested_at TIMESTAMP NOT NULL DEFAULT NOW(),
  approved_at TIMESTAMP NULL
);
CREATE TABLE IF NOT EXISTS payout_batches (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  batch_date DATE NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'OPEN',
  total_amount NUMERIC(14,2) NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS payout_transactions (
  id BIGSERIAL PRIMARY KEY,
  payout_batch_id BIGINT NULL REFERENCES payout_batches(id),
  payout_request_id BIGINT NOT NULL REFERENCES payout_requests(id),
  provider_transaction_id VARCHAR(120) NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'PENDING',
  processed_at TIMESTAMP NULL
);
CREATE TABLE IF NOT EXISTS platform_fees (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  fee_type VARCHAR(40) NOT NULL,
  percentage NUMERIC(7,4) NOT NULL,
  fixed_amount NUMERIC(14,2) NOT NULL DEFAULT 0,
  is_active BOOLEAN NOT NULL DEFAULT TRUE
);
CREATE TABLE IF NOT EXISTS split_payment_rules (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  rule_name VARCHAR(120) NOT NULL,
  destination_type VARCHAR(40) NOT NULL,
  destination_id BIGINT NOT NULL,
  percentage NUMERIC(7,4) NOT NULL,
  is_active BOOLEAN NOT NULL DEFAULT TRUE
);
CREATE TABLE IF NOT EXISTS split_payment_transactions (
  id BIGSERIAL PRIMARY KEY,
  transaction_id BIGINT NOT NULL REFERENCES business_wallet_transactions(id),
  split_rule_id BIGINT NOT NULL REFERENCES split_payment_rules(id),
  split_amount NUMERIC(14,2) NOT NULL,
  status VARCHAR(20) NOT NULL DEFAULT 'PENDING'
);
CREATE TABLE IF NOT EXISTS financial_reconciliation_logs (
  id BIGSERIAL PRIMARY KEY,
  tenant_id BIGINT NOT NULL,
  reconciled_at TIMESTAMP NOT NULL DEFAULT NOW(),
  reference_period VARCHAR(7) NOT NULL,
  discrepancies_found INT NOT NULL DEFAULT 0,
  notes TEXT NULL
);
CREATE OR REPLACE VIEW vw_business_wallet_summary AS
SELECT w.tenant_id,w.branch_id,b.available_balance,b.future_balance,b.blocked_balance,b.chargeback_reserve,
COALESCE((SELECT SUM(r.net_amount) FROM receivables r WHERE r.wallet_id=w.id AND r.status='OPEN'),0) open_receivables
FROM business_wallets w
LEFT JOIN business_wallet_balances b ON b.wallet_id=w.id;


-- ======================================================================
-- SOURCE: ScriptsSQL/130_professional_payouts.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS professional_financial_accounts (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, provider_name VARCHAR(60) NOT NULL DEFAULT 'MOCK_PROVIDER', account_token VARCHAR(120) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS professional_receivables (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, service_order_id BIGINT NULL, gross_amount NUMERIC(14,2) NOT NULL, net_amount NUMERIC(14,2) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'OPEN');
CREATE TABLE IF NOT EXISTS professional_payout_rules (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, rule_type VARCHAR(30) NOT NULL, execution_frequency VARCHAR(30) NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL DEFAULT 0, is_auto BOOLEAN NOT NULL DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS professional_payout_requests (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, requested_amount NUMERIC(14,2) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'REQUESTED', requested_at TIMESTAMP NOT NULL DEFAULT NOW(), approved_by BIGINT NULL, approved_at TIMESTAMP NULL);
CREATE TABLE IF NOT EXISTS professional_payout_statements (id BIGSERIAL PRIMARY KEY, payout_request_id BIGINT NOT NULL REFERENCES professional_payout_requests(id), statement_json JSONB NOT NULL, generated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS professional_payout_locks (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, lock_reason VARCHAR(200) NOT NULL, is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_professional_payouts AS SELECT ppr.tenant_id,ppr.professional_id,ppr.requested_amount,ppr.status,ppr.requested_at FROM professional_payout_requests ppr;


-- ======================================================================
-- SOURCE: ScriptsSQL/131_b2b_marketplace.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS b2b_marketplace_suppliers (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NULL, legal_name VARCHAR(160) NOT NULL, city VARCHAR(80), state_code CHAR(2), rating NUMERIC(3,2) NOT NULL DEFAULT 0, is_featured BOOLEAN NOT NULL DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS b2b_marketplace_categories (id BIGSERIAL PRIMARY KEY, category_name VARCHAR(120) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS b2b_marketplace_products (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), category_id BIGINT NOT NULL REFERENCES b2b_marketplace_categories(id), product_name VARCHAR(160) NOT NULL, sku VARCHAR(60), min_order_qty INT NOT NULL DEFAULT 1, is_active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS b2b_product_prices (id BIGSERIAL PRIMARY KEY, product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), price NUMERIC(14,2) NOT NULL, valid_from DATE NOT NULL DEFAULT CURRENT_DATE);
CREATE TABLE IF NOT EXISTS b2b_bulk_price_rules (id BIGSERIAL PRIMARY KEY, product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), min_qty INT NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_marketplace_orders (id BIGSERIAL PRIMARY KEY, buyer_tenant_id BIGINT NOT NULL, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), status VARCHAR(20) NOT NULL DEFAULT 'OPEN', total_amount NUMERIC(14,2) NOT NULL DEFAULT 0, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS b2b_marketplace_order_items (id BIGSERIAL PRIMARY KEY, order_id BIGINT NOT NULL REFERENCES b2b_marketplace_orders(id), product_id BIGINT NOT NULL REFERENCES b2b_marketplace_products(id), quantity INT NOT NULL, unit_price NUMERIC(14,2) NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_supplier_reviews (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), reviewer_tenant_id BIGINT NOT NULL, score INT NOT NULL, comment TEXT);
CREATE TABLE IF NOT EXISTS b2b_supplier_promotions (id BIGSERIAL PRIMARY KEY, supplier_id BIGINT NOT NULL REFERENCES b2b_marketplace_suppliers(id), title VARCHAR(140) NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL, starts_at DATE NOT NULL, ends_at DATE NOT NULL);
CREATE TABLE IF NOT EXISTS b2b_marketplace_commissions (id BIGSERIAL PRIMARY KEY, order_id BIGINT NOT NULL REFERENCES b2b_marketplace_orders(id), commission_percentage NUMERIC(7,4) NOT NULL, commission_amount NUMERIC(14,2) NOT NULL);
CREATE OR REPLACE VIEW vw_b2b_marketplace_sales AS SELECT o.id,o.buyer_tenant_id,o.total_amount,o.status,o.created_at FROM b2b_marketplace_orders o;


-- ======================================================================
-- SOURCE: ScriptsSQL/132_group_purchases.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS group_purchase_campaigns (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, campaign_name VARCHAR(160) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'OPEN', join_deadline DATE NOT NULL, min_total_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_participants (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), tenant_id BIGINT NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'JOINED');
CREATE TABLE IF NOT EXISTS group_purchase_items (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), product_id BIGINT NOT NULL, target_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_price_tiers (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), min_qty INT NOT NULL, unit_price NUMERIC(14,2) NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_commitments (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), participant_id BIGINT NOT NULL REFERENCES group_purchase_participants(id), committed_qty INT NOT NULL);
CREATE TABLE IF NOT EXISTS group_purchase_results (id BIGSERIAL PRIMARY KEY, campaign_id BIGINT NOT NULL REFERENCES group_purchase_campaigns(id), reached_qty INT NOT NULL, final_unit_price NUMERIC(14,2), closed_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_group_purchase_progress AS SELECT c.id,c.campaign_name,c.status,c.min_total_qty,COALESCE(SUM(cm.committed_qty),0) committed_qty FROM group_purchase_campaigns c LEFT JOIN group_purchase_commitments cm ON cm.campaign_id=c.id GROUP BY c.id;


