CREATE TABLE IF NOT EXISTS kiosk_accessibility_settings (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, high_contrast BOOLEAN NOT NULL DEFAULT FALSE, large_font BOOLEAN NOT NULL DEFAULT FALSE, simplified_navigation BOOLEAN NOT NULL DEFAULT FALSE, senior_mode BOOLEAN NOT NULL DEFAULT FALSE, updated_at TIMESTAMP NOT NULL DEFAULT NOW());
