CREATE TABLE IF NOT EXISTS commercial_opportunity_types (id BIGSERIAL PRIMARY KEY, code VARCHAR(60) NOT NULL UNIQUE, description TEXT NOT NULL, default_priority INT NOT NULL);
CREATE TABLE IF NOT EXISTS commercial_opportunity_center (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, opportunity_type_id BIGINT NOT NULL REFERENCES commercial_opportunity_types(id), title VARCHAR(160) NOT NULL, expected_impact NUMERIC(14,2) NOT NULL DEFAULT 0, status VARCHAR(20) NOT NULL DEFAULT 'OPEN', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS commercial_opportunity_actions (id BIGSERIAL PRIMARY KEY, opportunity_id BIGINT NOT NULL REFERENCES commercial_opportunity_center(id), action_name VARCHAR(120) NOT NULL, executed_by BIGINT NULL, executed_at TIMESTAMP NULL, status VARCHAR(20) NOT NULL DEFAULT 'PENDING');
CREATE TABLE IF NOT EXISTS commercial_opportunity_results (id BIGSERIAL PRIMARY KEY, action_id BIGINT NOT NULL REFERENCES commercial_opportunity_actions(id), result_json JSONB NOT NULL, captured_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_opportunity_center AS SELECT c.tenant_id,c.title,c.expected_impact,c.status,t.code opportunity_type FROM commercial_opportunity_center c JOIN commercial_opportunity_types t ON t.id=c.opportunity_type_id;


