-- SOURCE: ScriptsSQL/140_platform_monetization.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS platform_revenue_streams (id BIGSERIAL PRIMARY KEY, stream_name VARCHAR(120) NOT NULL UNIQUE, stream_type VARCHAR(40) NOT NULL, is_active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS platform_commission_rules (id BIGSERIAL PRIMARY KEY, stream_id BIGINT NOT NULL REFERENCES platform_revenue_streams(id), percentage NUMERIC(7,4) NOT NULL, fixed_fee NUMERIC(14,2) NOT NULL DEFAULT 0, starts_at DATE NOT NULL DEFAULT CURRENT_DATE);
CREATE TABLE IF NOT EXISTS platform_revenue_transactions (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NULL, stream_id BIGINT NOT NULL REFERENCES platform_revenue_streams(id), gross_amount NUMERIC(14,2) NOT NULL, net_amount NUMERIC(14,2) NOT NULL, happened_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS sponsored_placements (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, placement_area VARCHAR(80) NOT NULL, starts_at DATE NOT NULL, ends_at DATE NOT NULL, amount NUMERIC(14,2) NOT NULL);
CREATE TABLE IF NOT EXISTS premium_feature_usage (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, feature_code VARCHAR(60) NOT NULL, usage_count INT NOT NULL DEFAULT 0, updated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS platform_revenue_reports (id BIGSERIAL PRIMARY KEY, reference_month VARCHAR(7) NOT NULL, total_gross NUMERIC(14,2) NOT NULL, total_net NUMERIC(14,2) NOT NULL, generated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_platform_revenue AS SELECT DATE_TRUNC('month',happened_at)::date month_ref,SUM(gross_amount) total_gross,SUM(net_amount) total_net FROM platform_revenue_transactions GROUP BY 1;


