-- Public API + Developer Portal
CREATE TABLE IF NOT EXISTS developer_accounts (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NULL, name VARCHAR(160) NOT NULL, email VARCHAR(190) NOT NULL UNIQUE, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_apps (id BIGSERIAL PRIMARY KEY, account_id BIGINT NOT NULL REFERENCES developer_accounts(id), app_name VARCHAR(160) NOT NULL, environment VARCHAR(20) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', callback_url TEXT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_api_keys (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), key_prefix VARCHAR(20) NOT NULL, key_hash VARCHAR(256) NOT NULL, expires_at TIMESTAMP NULL, revoked_at TIMESTAMP NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_app_permissions (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), permission_code VARCHAR(120) NOT NULL, allowed BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_api_usage_logs (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), path VARCHAR(255) NOT NULL, method VARCHAR(10) NOT NULL, status_code INT NOT NULL, latency_ms INT NOT NULL DEFAULT 0, requested_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_rate_limits (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), period VARCHAR(20) NOT NULL, max_requests INT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_key_rotations (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), old_key_id BIGINT NULL, new_key_id BIGINT NULL, rotated_at TIMESTAMP NOT NULL DEFAULT NOW(), rotated_by VARCHAR(120) NOT NULL);
CREATE TABLE IF NOT EXISTS developer_sandbox_data (id BIGSERIAL PRIMARY KEY, app_id BIGINT NOT NULL REFERENCES developer_apps(id), payload JSONB NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS developer_terms_acceptance (id BIGSERIAL PRIMARY KEY, account_id BIGINT NOT NULL REFERENCES developer_accounts(id), terms_version VARCHAR(30) NOT NULL, accepted_at TIMESTAMP NOT NULL DEFAULT NOW(), ip_address VARCHAR(64) NULL);


-- ======================================================================
-- SOURCE: ScriptsSQL/143_partner_integrators.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS technology_partners (id BIGSERIAL PRIMARY KEY, name VARCHAR(180) NOT NULL, partner_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_applications (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), app_name VARCHAR(160) NOT NULL, integration_type VARCHAR(80) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'ACTIVE', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_contracts (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), contract_code VARCHAR(60) NOT NULL, starts_at DATE NOT NULL, ends_at DATE NULL, status VARCHAR(30) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS partner_certifications (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), certification_name VARCHAR(140) NOT NULL, level VARCHAR(40) NOT NULL, valid_until DATE NULL);
CREATE TABLE IF NOT EXISTS partner_sla_agreements (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), response_sla_minutes INT NOT NULL, resolution_sla_minutes INT NOT NULL, active BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS partner_revenue_share_rules (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), rule_name VARCHAR(120) NOT NULL, percentage NUMERIC(5,2) NOT NULL);
CREATE TABLE IF NOT EXISTS partner_support_cases (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), subject VARCHAR(200) NOT NULL, severity VARCHAR(20) NOT NULL, status VARCHAR(30) NOT NULL DEFAULT 'OPEN', created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS partner_integration_reviews (id BIGSERIAL PRIMARY KEY, partner_id BIGINT NOT NULL REFERENCES technology_partners(id), score INT NOT NULL CHECK (score BETWEEN 1 AND 5), notes TEXT NULL, reviewed_at TIMESTAMP NOT NULL DEFAULT NOW());


