-- SOURCE: ScriptsSQL/147_command_center.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS command_center_snapshots (id BIGSERIAL PRIMARY KEY, captured_at TIMESTAMP DEFAULT NOW(), payload JSONB NOT NULL);
CREATE TABLE IF NOT EXISTS regional_operations (id BIGSERIAL PRIMARY KEY, region VARCHAR(80) NOT NULL, active_tenants INT NOT NULL DEFAULT 0);
CREATE TABLE IF NOT EXISTS regional_platform_metrics (id BIGSERIAL PRIMARY KEY, region VARCHAR(80), metric_name VARCHAR(80), metric_value NUMERIC(18,2), captured_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS national_alerts (id BIGSERIAL PRIMARY KEY, severity VARCHAR(20), message TEXT, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS platform_health_events (id BIGSERIAL PRIMARY KEY, component VARCHAR(80), status VARCHAR(20), event_time TIMESTAMP DEFAULT NOW());


-- ======================================================================
-- SOURCE: ScriptsSQL/148_ai_autonomous_agents.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS ai_agents (id BIGSERIAL PRIMARY KEY, name VARCHAR(80), domain VARCHAR(80), active BOOLEAN DEFAULT TRUE);
CREATE TABLE IF NOT EXISTS ai_agent_runs (id BIGSERIAL PRIMARY KEY, agent_id BIGINT REFERENCES ai_agents(id), context JSONB, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS ai_agent_suggestions (id BIGSERIAL PRIMARY KEY, run_id BIGINT REFERENCES ai_agent_runs(id), priority VARCHAR(20), impact VARCHAR(20), suggestion TEXT);
CREATE TABLE IF NOT EXISTS ai_agent_actions (id BIGSERIAL PRIMARY KEY, run_id BIGINT REFERENCES ai_agent_runs(id), action_type VARCHAR(80), requires_approval BOOLEAN DEFAULT TRUE, status VARCHAR(30) DEFAULT 'PENDING');
CREATE TABLE IF NOT EXISTS ai_agent_action_approvals (id BIGSERIAL PRIMARY KEY, action_id BIGINT REFERENCES ai_agent_actions(id), approver VARCHAR(120), status VARCHAR(20), approved_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS ai_agent_feedback (id BIGSERIAL PRIMARY KEY, run_id BIGINT REFERENCES ai_agent_runs(id), feedback_score INT, comments TEXT);
CREATE TABLE IF NOT EXISTS ai_agent_guardrails (id BIGSERIAL PRIMARY KEY, action_type VARCHAR(80), rule_text TEXT NOT NULL);
CREATE TABLE IF NOT EXISTS ai_agent_execution_logs (id BIGSERIAL PRIMARY KEY, run_id BIGINT REFERENCES ai_agent_runs(id), log_level VARCHAR(20), message TEXT, created_at TIMESTAMP DEFAULT NOW());


-- ======================================================================
-- SOURCE: ScriptsSQL/149_change_release_management.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS change_requests (id BIGSERIAL PRIMARY KEY, title VARCHAR(180), risk_level VARCHAR(20), status VARCHAR(30) DEFAULT 'OPEN');
CREATE TABLE IF NOT EXISTS change_approvals (id BIGSERIAL PRIMARY KEY, change_request_id BIGINT REFERENCES change_requests(id), approver VARCHAR(120), status VARCHAR(20));
CREATE TABLE IF NOT EXISTS release_plans (id BIGSERIAL PRIMARY KEY, change_request_id BIGINT REFERENCES change_requests(id), release_window TIMESTAMP, version VARCHAR(40));
CREATE TABLE IF NOT EXISTS release_checklists (id BIGSERIAL PRIMARY KEY, release_plan_id BIGINT REFERENCES release_plans(id), item TEXT, done BOOLEAN DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS rollback_plans (id BIGSERIAL PRIMARY KEY, release_plan_id BIGINT REFERENCES release_plans(id), steps TEXT);
CREATE TABLE IF NOT EXISTS release_notes (id BIGSERIAL PRIMARY KEY, release_plan_id BIGINT REFERENCES release_plans(id), notes TEXT);
CREATE TABLE IF NOT EXISTS release_communications (id BIGSERIAL PRIMARY KEY, release_plan_id BIGINT REFERENCES release_plans(id), audience VARCHAR(80), message TEXT);


-- ======================================================================
-- SOURCE: ScriptsSQL/150_business_continuity.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS business_continuity_plans (id BIGSERIAL PRIMARY KEY, name VARCHAR(160), rto_minutes INT, rpo_minutes INT);
CREATE TABLE IF NOT EXISTS disaster_recovery_plans (id BIGSERIAL PRIMARY KEY, continuity_plan_id BIGINT REFERENCES business_continuity_plans(id), dr_region VARCHAR(80), status VARCHAR(30));
CREATE TABLE IF NOT EXISTS recovery_tests (id BIGSERIAL PRIMARY KEY, dr_plan_id BIGINT REFERENCES disaster_recovery_plans(id), tested_at TIMESTAMP, result VARCHAR(30));
CREATE TABLE IF NOT EXISTS backup_status_logs (id BIGSERIAL PRIMARY KEY, component VARCHAR(120), backup_status VARCHAR(30), checked_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS critical_dependencies (id BIGSERIAL PRIMARY KEY, dependency_name VARCHAR(120), owner VARCHAR(120));
CREATE TABLE IF NOT EXISTS emergency_contacts (id BIGSERIAL PRIMARY KEY, name VARCHAR(120), role_name VARCHAR(80), phone VARCHAR(40));
CREATE TABLE IF NOT EXISTS continuity_evidences (id BIGSERIAL PRIMARY KEY, continuity_plan_id BIGINT REFERENCES business_continuity_plans(id), evidence TEXT);


-- ======================================================================
-- SOURCE: ScriptsSQL/151_immutable_audit.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS immutable_audit_logs (id BIGSERIAL PRIMARY KEY, event_type VARCHAR(80), event_payload JSONB, event_hash VARCHAR(128), previous_hash VARCHAR(128), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS audit_hash_chains (id BIGSERIAL PRIMARY KEY, chain_name VARCHAR(80), latest_hash VARCHAR(128), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS audit_integrity_checks (id BIGSERIAL PRIMARY KEY, checked_at TIMESTAMP DEFAULT NOW(), valid BOOLEAN, details TEXT);
CREATE TABLE IF NOT EXISTS audit_exports (id BIGSERIAL PRIMARY KEY, exported_at TIMESTAMP DEFAULT NOW(), exported_by VARCHAR(120), file_ref TEXT);


-- ======================================================================
-- SOURCE: ScriptsSQL/152_advanced_compliance.sql
-- ======================================================================

CREATE TABLE IF NOT EXISTS compliance_frameworks (id BIGSERIAL PRIMARY KEY, name VARCHAR(100), version VARCHAR(40));
CREATE TABLE IF NOT EXISTS compliance_controls (id BIGSERIAL PRIMARY KEY, framework_id BIGINT REFERENCES compliance_frameworks(id), control_code VARCHAR(60), title VARCHAR(180));
CREATE TABLE IF NOT EXISTS compliance_control_evidences (id BIGSERIAL PRIMARY KEY, control_id BIGINT REFERENCES compliance_controls(id), evidence TEXT, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS compliance_assessments (id BIGSERIAL PRIMARY KEY, framework_id BIGINT REFERENCES compliance_frameworks(id), assessment_date DATE, score NUMERIC(5,2));
CREATE TABLE IF NOT EXISTS compliance_nonconformities (id BIGSERIAL PRIMARY KEY, assessment_id BIGINT REFERENCES compliance_assessments(id), description TEXT, severity VARCHAR(20), status VARCHAR(20));
CREATE TABLE IF NOT EXISTS compliance_scores (id BIGSERIAL PRIMARY KEY, framework_id BIGINT REFERENCES compliance_frameworks(id), score NUMERIC(5,2), calculated_at TIMESTAMP DEFAULT NOW());


-- ======================================================================
-- SOURCE: ScriptsSQL/153_enterprise_dashboard_views.sql
-- ======================================================================

CREATE OR REPLACE VIEW vw_public_api_usage AS SELECT app_id, count(*) total_calls FROM developer_api_usage_logs GROUP BY app_id;
CREATE OR REPLACE VIEW vw_developer_apps_status AS SELECT environment, status, count(*) apps FROM developer_apps GROUP BY environment,status;
CREATE OR REPLACE VIEW vw_partner_integrations AS SELECT p.name, count(a.id) applications FROM technology_partners p LEFT JOIN partner_applications a ON p.id=a.partner_id GROUP BY p.name;
CREATE OR REPLACE VIEW vw_governance_pending_approvals AS SELECT * FROM governance_approvals WHERE status='PENDING';
CREATE OR REPLACE VIEW vw_enterprise_risk_heatmap AS SELECT category_id, probability, impact, count(*) total FROM enterprise_risks GROUP BY category_id, probability, impact;
CREATE OR REPLACE VIEW vw_incident_sla_summary AS SELECT i.id incident_id, s.response_minutes, s.resolution_minutes, s.breached FROM incidents i LEFT JOIN incident_sla_tracking s ON i.id=s.incident_id;
CREATE OR REPLACE VIEW vw_command_center_national AS SELECT region, sum(active_tenants) active_tenants FROM regional_operations GROUP BY region;
CREATE OR REPLACE VIEW vw_ai_agent_suggestions AS SELECT a.name agent_name, s.priority, s.impact, s.suggestion FROM ai_agent_suggestions s JOIN ai_agent_runs r ON r.id=s.run_id JOIN ai_agents a ON a.id=r.agent_id;
CREATE OR REPLACE VIEW vw_change_release_status AS SELECT c.title, c.status, rp.version FROM change_requests c LEFT JOIN release_plans rp ON rp.change_request_id=c.id;
CREATE OR REPLACE VIEW vw_business_continuity_readiness AS SELECT name, rto_minutes, rpo_minutes FROM business_continuity_plans;
CREATE OR REPLACE VIEW vw_immutable_audit_integrity AS SELECT checked_at, valid, details FROM audit_integrity_checks;
CREATE OR REPLACE VIEW vw_advanced_compliance_score AS SELECT f.name framework, avg(s.score) avg_score FROM compliance_frameworks f JOIN compliance_scores s ON s.framework_id=f.id GROUP BY f.name;
CREATE OR REPLACE VIEW vw_enterprise_dashboard AS SELECT now() captured_at;


